def is_enabled(self, level):
    """Check if a log level would produce output.

    Returns True if at least one handler is configured to process
    messages at the given level.
    """
    level_no = self.level(level).no if isinstance(level, str) else level
    for handler in self._core.handlers.values():
        if handler.levelno <= level_no:
            return True
    return False

