"""Tests for Logger.catch() decorator."""

import pytest
from loguru import logger


def test_catch_suppresses_exception():
    """catch() suppresses exceptions by default."""
    @logger.catch(default=None)
    def failing():
        raise ValueError('test error')

    result = failing()  # Should not raise
    assert result is None


def test_catch_reraise():
    """catch(reraise=True) logs then reraises."""
    @logger.catch(reraise=True)
    def failing():
        raise RuntimeError('reraised')

    with pytest.raises(RuntimeError, match='reraised'):
        failing()


def test_catch_specific_exception():
    """catch(exception=Type) only catches that type."""
    @logger.catch(exception=ValueError, default=-1)
    def might_fail(x):
        if x < 0:
            raise ValueError('negative')
        return x

    assert might_fail(-1) == -1  # ValueError caught
    assert might_fail(5) == 5   # No exception
